import { useState } from "react";

import { Avatar, AvatarFallback, AvatarImage } from "../avatar";
import { Button } from "../button";
import { Textarea } from "../textarea";
import { cn } from "../utils/cn";

type Comment = {
  id: string;
  author: string;
  avatarUrl?: string;
  content: string;
  timestamp: string;
};

type CommentThreadProps = {
  comments: Comment[];
  onAddComment?: (content: string) => void;
  placeholder?: string;
  className?: string;
};

function CommentItem({ comment }: { comment: Comment }) {
  const initials = comment.author
    .split(" ")
    .map((n) => n[0])
    .join("")
    .toUpperCase()
    .slice(0, 2);

  return (
    <div data-slot="comment-item" className="flex gap-3">
      <Avatar size="sm">
        {comment.avatarUrl ? (
          <AvatarImage src={comment.avatarUrl} alt={comment.author} />
        ) : null}
        <AvatarFallback>{initials}</AvatarFallback>
      </Avatar>
      <div className="flex flex-1 flex-col gap-1">
        <div className="flex items-center gap-2">
          <span className="text-sm font-medium">{comment.author}</span>
          <span className="text-xs text-muted-foreground">
            {comment.timestamp}
          </span>
        </div>
        <p className="text-sm">{comment.content}</p>
      </div>
    </div>
  );
}

function CommentForm({
  onAddComment,
  placeholder = "Write a comment...",
}: {
  onAddComment: (content: string) => void;
  placeholder?: string;
}) {
  const [value, setValue] = useState("");

  function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    const trimmed = value.trim();
    if (!trimmed) return;
    onAddComment(trimmed);
    setValue("");
  }

  return (
    <form
      data-slot="comment-form"
      onSubmit={handleSubmit}
      className="flex flex-col gap-2"
    >
      <Textarea
        value={value}
        onChange={(e) => setValue(e.target.value)}
        placeholder={placeholder}
      />
      <div className="flex justify-end">
        <Button type="submit" size="sm" disabled={!value.trim()}>
          Submit
        </Button>
      </div>
    </form>
  );
}

function CommentThread({
  comments,
  onAddComment,
  placeholder,
  className,
}: CommentThreadProps) {
  return (
    <div
      data-slot="comment-thread"
      className={cn("flex flex-col gap-4", className)}
    >
      {comments.map((comment) => (
        <CommentItem key={comment.id} comment={comment} />
      ))}
      {onAddComment ? (
        <CommentForm onAddComment={onAddComment} placeholder={placeholder} />
      ) : null}
    </div>
  );
}

export { CommentThread, CommentItem, CommentForm };
export type { Comment, CommentThreadProps };
